<!-- SideNavBar (Shared Component - Desktop Only) -->\n<aside class=\"hidden lg:flex flex-col h-full w-64 fixed left-0 top-0 pt-20 bg-surface-container-low border-r border-outline-variant z-40\">\n<div class=\"px-6 mb-8\">\n<h2 class=\"font-label-caps text-label-caps text-on-surface-variant opacity-60\">ADMINISTRATIVE LAYERS</h2>\n</div>\n<nav class=\"flex-1 space-y-1\">\n<a class=\"flex items-center gap-3 py-3 px-4 mx-2 bg-secondary-container text-on-secondary-container rounded-lg translate-x-1 duration-150\" href=\"#\">\n<span class=\"material-symbols-outlined\" style=\"font-variation-settings: 'FILL' 1;\">payments</span>\n<span class=\"font-label-sm text-label-sm\">Economic Transformation</span>\n</a>\n<a class=\"flex items-center gap-3 py-3 px-4 mx-2 text-on-surface-variant hover:bg-surface-variant/50 rounded-lg transition-all\" href=\"#\">\n<span class=\"material-symbols-outlined\">account_balance</span>\n<span class=\"font-label-sm text-label-sm\">Digital Government</span>\n</a>\n<a class=\"flex items-center gap-3 py-3 px-4 mx-2 text-on-surface-variant hover:bg-surface-variant/50 rounded-lg transition-all\" href=\"#\">\n<span class=\"material-symbols-outlined\">mitre</span>\n<span class=\"font-label-sm text-label-sm\">Transparent Governance</span>\n</a>\n<a class=\"flex items-center gap-3 py-3 px-4 mx-2 text-on-surface-variant hover:bg-surface-variant/50 rounded-lg transition-all\" href=\"#\">\n<span class=\"material-symbols-outlined\">security</span>\n<span class=\"font-label-sm text-label-sm\">Public Trust</span>\n</a>\n</nav>\n<div class=\"p-6 border-t border-outline-variant\">\n<button class=\"w-full py-3 bg-forest-deep text-white rounded-lg font-label-caps text-label-caps hover:bg-primary transition-all\">Citizen Feedback</button>\n<div class=\"mt-6 flex items-center justify-around text-on-surface-variant\">\n<span class=\"material-symbols-outlined cursor-pointer hover:text-primary\">settings</span>\n<span class=\"material-symbols-outlined cursor-pointer hover:text-primary\">help</span>\n</div>\n</div>\n</aside>\n<!-- Main Content Area -->\n<main class=\"lg:pl-64 pt-20 pb-12 min-h-screen\">\n<div class=\"max-w-[1280px] mx-auto px-5 md:px-16 py-8\">\n<!-- Hero Dashboard Header -->\n<header class=\"mb-12\">\n<div class=\"flex flex-col md:flex-row md:items-end justify-between gap-6\">\n<div>\n<span class=\"font-label-caps text-label-caps text-brass-accent\">STATE OPERATING SYSTEM</span>\n<h1 class=\"font-headline-xl text-headline-xl text-forest-deep mt-2\">Dashboard Central</h1>\n</div>\n<div class=\"flex gap-4\">\n<div class=\"bg-surface-container-highest p-4 rounded-xl flex items-center gap-4 border border-outline-variant\">\n<div class=\"w-12 h-12 rounded-full bg-emerald-vibrant flex items-center justify-center text-white\">\n<span class=\"material-symbols-outlined\">trending_up</span>\n</div>\n<div>\n<p class=\"font-label-caps text-[10px] text-on-surface-variant\">GDP GROWTH</p>\n<p class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold text-forest-deep\">+4.2%</p>\n</div>\n</div>\n<div class=\"bg-surface-container-highest p-4 rounded-xl flex items-center gap-4 border border-outline-variant\">\n<div class=\"w-12 h-12 rounded-full bg-brass-accent flex items-center justify-center text-white\">\n<span class=\"material-symbols-outlined\">verified_user</span>\n</div>\n<div>\n<p class=\"font-label-caps text-[10px] text-on-surface-variant\">DIGITAL LITERACY</p>\n<p class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold text-forest-deep\">68%</p>\n</div>\n</div>\n</div>\n</div>\n</header>\n<!-- Bento Grid Layout -->\n<div class=\"grid grid-cols-1 md:grid-cols-12 gap-6\">\n<!-- Governor's Message -->\n<section class=\"md:col-span-8 bg-forest-deep rounded-xl p-8 text-white relative overflow-hidden flex flex-col justify-between min-h-[340px]\">\n<div class=\"relative z-10 max-w-lg\">\n<span class=\"inline-block px-3 py-1 bg-brass-accent/20 border border-brass-accent rounded-full text-[10px] font-label-caps text-brass-accent mb-6\">OFFICE OF THE GOVERNOR</span>\n<h2 class=\"font-headline-lg text-headline-lg mb-4\">\"Building the foundation for a sustainable, digital economy in the heart of Igboland.\"</h2>\n<p class=\"font-body-md text-body-md text-surface-variant/80 mb-6\">Our administration is committed to the Abia 2035 vision, transforming the state through infrastructure, security, and digital empowerment.</p>\n<div class=\"flex items-center gap-3\">\n<div class=\"w-10 h-10 rounded-full bg-white/10 border border-white/20\"></div>\n<div>\n<p class=\"font-label-sm text-label-sm font-bold\">His Excellency, Dr. Alex Otti</p>\n<p class=\"font-label-sm text-[10px] opacity-70 uppercase\">Executive Governor of Abia State</p>\n</div>\n</div>\n</div>\n<!-- Decorative Asset -->\n<div class=\"absolute right-0 bottom-0 top-0 w-1/2 opacity-20 pointer-events-none\">\n\n</div>\n</section>\n<!-- Abia 2035 Tracker -->\n<section class=\"md:col-span-4 bg-white border border-outline-variant rounded-xl p-6 flex flex-col\">\n<div class=\"flex justify-between items-start mb-8\">\n<div>\n<h3 class=\"font-label-caps text-label-caps text-on-surface-variant\">ABIA 2035 TRACKER</h3>\n<p class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold text-forest-deep mt-1\">Goal: Industrial Hub</p>\n</div>\n<span class=\"material-symbols-outlined text-brass-accent\">flag</span>\n</div>\n<div class=\"space-y-6 flex-1\">\n<div>\n<div class=\"flex justify-between text-[11px] font-label-caps mb-2\">\n<span>POWER ELECTRIFICATION</span>\n<span class=\"text-emerald-vibrant\">72%</span>\n</div>\n<div class=\"w-full bg-surface-container h-2 rounded-full overflow-hidden\">\n<div class=\"bg-emerald-vibrant h-full w-[72%]\"></div>\n</div>\n</div>\n<div>\n<div class=\"flex justify-between text-[11px] font-label-caps mb-2\">\n<span>DIGITAL GOV MIGRATION</span>\n<span class=\"text-brass-accent\">45%</span>\n</div>\n<div class=\"w-full bg-surface-container h-2 rounded-full overflow-hidden\">\n<div class=\"bg-brass-accent h-full w-[45%]\"></div>\n</div>\n</div>\n<div>\n<div class=\"flex justify-between text-[11px] font-label-caps mb-2\">\n<span>SECURITY COVERAGE</span>\n<span class=\"text-status-security\">88%</span>\n</div>\n<div class=\"w-full bg-surface-container h-2 rounded-full overflow-hidden\">\n<div class=\"bg-status-security h-full w-[88%]\"></div>\n</div>\n</div>\n</div>\n<button class=\"mt-8 text-primary font-label-caps text-label-caps flex items-center gap-2 hover:underline\">\n                        VIEW FULL ROADMAP <span class=\"material-symbols-outlined text-sm\">arrow_forward</span>\n</button>\n</section>\n<!-- Transformation Layers (Icon Grid) -->\n<section class=\"md:col-span-12 grid grid-cols-2 lg:grid-cols-4 gap-6\">\n<div class=\"group bg-white border border-outline-variant rounded-xl p-6 hover:shadow-lg transition-all cursor-pointer\">\n<div class=\"w-12 h-12 rounded-lg bg-status-economic/10 text-status-economic flex items-center justify-center mb-4 group-hover:scale-110 transition-transform\">\n<span class=\"material-symbols-outlined\">finance_chip</span>\n</div>\n<h4 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold mb-2\">Economy</h4>\n<p class=\"font-body-md text-sm text-on-surface-variant\">Market digitization &amp; SME support hubs.</p>\n</div>\n<div class=\"group bg-white border border-outline-variant rounded-xl p-6 hover:shadow-lg transition-all cursor-pointer\">\n<div class=\"w-12 h-12 rounded-lg bg-emerald-vibrant/10 text-emerald-vibrant flex items-center justify-center mb-4 group-hover:scale-110 transition-transform\">\n<span class=\"material-symbols-outlined\">cloud_done</span>\n</div>\n<h4 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold mb-2\">Digital Gov</h4>\n<p class=\"font-body-md text-sm text-on-surface-variant\">Paperless administration &amp; citizen portal.</p>\n</div>\n<div class=\"group bg-white border border-outline-variant rounded-xl p-6 hover:shadow-lg transition-all cursor-pointer\">\n<div class=\"w-12 h-12 rounded-lg bg-brass-accent/10 text-brass-accent flex items-center justify-center mb-4 group-hover:scale-110 transition-transform\">\n<span class=\"material-symbols-outlined\">visibility</span>\n</div>\n<h4 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold mb-2\">Governance</h4>\n<p class=\"font-body-md text-sm text-on-surface-variant\">Open data initiatives &amp; budget tracking.</p>\n</div>\n<div class=\"group bg-white border border-outline-variant rounded-xl p-6 hover:shadow-lg transition-all cursor-pointer\">\n<div class=\"w-12 h-12 rounded-lg bg-status-security/10 text-status-security flex items-center justify-center mb-4 group-hover:scale-110 transition-transform\">\n<span class=\"material-symbols-outlined\">shield_with_heart</span>\n</div>\n<h4 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold mb-2\">Security</h4>\n<p class=\"font-body-md text-sm text-on-surface-variant\">Community policing &amp; emergency response.</p>\n</div>\n</section>\n<!-- Invest Abia Carousel (Latest Opportunities) -->\n<section class=\"md:col-span-12\">\n<div class=\"flex items-center justify-between mb-6\">\n<h3 class=\"font-label-caps text-label-caps text-on-surface-variant\">INVEST ABIA: LATEST OPPORTUNITIES</h3>\n<div class=\"flex gap-2\">\n<button class=\"w-10 h-10 rounded-full border border-outline-variant flex items-center justify-center hover:bg-surface-container transition-colors\">\n<span class=\"material-symbols-outlined\">chevron_left</span>\n</button>\n<button class=\"w-10 h-10 rounded-full border border-outline-variant flex items-center justify-center hover:bg-surface-container transition-colors\">\n<span class=\"material-symbols-outlined\">chevron_right</span>\n</button>\n</div>\n</div>\n<div class=\"flex gap-6 overflow-x-auto pb-4 no-scrollbar\">\n<div class=\"min-w-[300px] bg-white border border-outline-variant rounded-xl overflow-hidden group\">\n<div class=\"h-40 bg-surface-container-high relative\">\n<img class=\"w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\" data-alt=\"A high-altitude drone view of a modern industrial park under construction in a lush tropical African landscape. The scene features large warehouse structures with silver roofs, paved roads, and clear architectural planning. Sunlight reflects off glass windows, projecting a sense of economic progress and industrialization within the Abia State design system.\" src=\"https://lh3.googleusercontent.com/aida-public/AB6AXuDpMNkJKXCibgCp2usmmiejkWUJvg7rGq4mYEL-Yu_tE2jABGkwU7DbX46oYJxj5W5lIXJOX2LWRcNOvIiDke6GtN2mWhJhtTy9OU4JJ9_kDOOxMNy5VPfatEXHu8hr5Bv864m6RVjKa2qlouHdmgn-RKPIIo4h1zQ21ImL1BjtlqAD7TjZuiOERMmhesvO19oCK168l_gByYTpyjUpiiKRb0s4OGKRm3cmuv5GSwcNvypp8QrcpGQGL6MraPppz4Ex3L9OoHvsrj8\">\n<span class=\"absolute top-4 left-4 bg-emerald-vibrant text-white text-[10px] font-label-caps px-2 py-1 rounded\">MANUFACTURING</span>\n</div>\n<div class=\"p-6\">\n<h5 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold text-forest-deep mb-2\">Aba Textile Hub Phase 2</h5>\n<p class=\"text-sm text-on-surface-variant mb-4\">Investment opportunity in modern garment production facilities.</p>\n<div class=\"flex items-center justify-between\">\n<span class=\"font-label-sm text-brass-accent\">EST. ROI: 12%</span>\n<span class=\"material-symbols-outlined text-on-surface-variant\">open_in_new</span>\n</div>\n</div>\n</div>\n<div class=\"min-w-[300px] bg-white border border-outline-variant rounded-xl overflow-hidden group\">\n<div class=\"h-40 bg-surface-container-high relative\">\n<img class=\"w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\" data-alt=\"A macro shot of digital data visualizations on a sleek, high-resolution monitor. Bright blue and gold charts and graphs illustrate economic growth and market trends. The lighting is low and cinematic, emphasizing the professional, data-driven nature of the Abia One State Operating System and its focus on transparent governance.\" src=\"https://lh3.googleusercontent.com/aida-public/AB6AXuB_ru-I8D-ulH-TCv05rLg2oLqLRdor6QIFO9nApsmmWVJOhTeWvmMoa1V-KNo6B7dE2pcle1qTmNbJ-OFjT2K8aMnfYG1Hps96YlgFkK_FZeO7qSavYxMTRpIUXIzujbLvaq12kMke6z8hGY42dwkqs8327v8Z-sIBOl1zY_4sIjCFE-u_VYkQP5E1mWVbaw_dvFEFb9DWGUF3TgaroSfJJDurBvcIxF6-p5l6iho_FtiG6bHdOjNinS16fuhOaqNMC4ML2MIP2qo\">\n<span class=\"absolute top-4 left-4 bg-status-economic text-white text-[10px] font-label-caps px-2 py-1 rounded\">TECHNOLOGY</span>\n</div>\n<div class=\"p-6\">\n<h5 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold text-forest-deep mb-2\">Umuahia Tech Innovation Lab</h5>\n<p class=\"text-sm text-on-surface-variant mb-4\">Funding call for the regional AI and software development incubator.</p>\n<div class=\"flex items-center justify-between\">\n<span class=\"font-label-sm text-brass-accent\">EST. ROI: 18%</span>\n<span class=\"material-symbols-outlined text-on-surface-variant\">open_in_new</span>\n</div>\n</div>\n</div>\n<div class=\"min-w-[300px] bg-white border border-outline-variant rounded-xl overflow-hidden group\">\n<div class=\"h-40 bg-surface-container-high relative\">\n<img class=\"w-full h-full object-cover group-hover:scale-105 transition-transform duration-500\" data-alt=\"A wide panoramic shot of fertile agricultural farmlands in Nigeria under a golden sunset. Vibrant green crops are arranged in neat rows stretching toward the horizon, where tropical trees stand tall. The lighting is warm and inspiring, capturing the essence of sustainable agriculture and food security, a core pillar of the Abia 2035 state vision.\" src=\"https://lh3.googleusercontent.com/aida-public/AB6AXuC3O_7UoItnP2ihDFlEDU_cz5N5PhnUGQ0kD6p5He05xD8kKZBAWYJN7oi0Mb6yqOesd03Gqa0fJ85rM5PmxLNbokm1IwC6icfHVrxUeuNd3PVxsmaazO0lADKvTbm_jfweuSJWe0xtVbA-tM3ErwdbvYHfklSy6MaQ3Bs0qQyoYtKoCCPFAZg5hfWlqvizEXFTo7bNILHmCO87GhShlolO9ENY5zCkTeiUgkHfogqVvmVLJ9dt-oSdaYoNiJrAhKnksI-zH_tbNuo\">\n<span class=\"absolute top-4 left-4 bg-forest-deep text-white text-[10px] font-label-caps px-2 py-1 rounded\">AGRI-TECH</span>\n</div>\n<div class=\"p-6\">\n<h5 class=\"font-headline-lg-mobile text-headline-lg-mobile font-bold text-forest-deep mb-2\">Sustainable Palm Oil Estates</h5>\n<p class=\"text-sm text-on-surface-variant mb-4\">Modernizing traditional palm oil processing for global export.</p>\n<div class=\"flex items-center justify-between\">\n<span class=\"font-label-sm text-brass-accent\">EST. ROI: 15%</span>\n<span class=\"material-symbols-outlined text-on-surface-variant\">open_in_new</span>\n</div>\n</div>\n</div>\n</div>\n</section>\n</div>\n</div>\n</main>\n<!-- Footer (Shared Component) -->\n<footer class=\"lg:pl-64 w-full px-5 md:px-16 bg-surface-container-highest mt-auto border-t border-outline-variant py-12\">\n<div class=\"max-w-[1280px] mx-auto\">\n<div class=\"grid grid-cols-1 md:grid-cols-3 gap-12 mb-12\">\n<div class=\"space-y-4\">\n<span class=\"font-headline-lg text-headline-lg text-forest-deep font-bold\">ABIA ONE</span>\n<p class=\"font-body-md text-body-md text-on-surface-variant\">The unified digital interface for governance, commerce, and security in Abia State. Built for the citizens, by the future.</p>\n</div>\n<div class=\"grid grid-cols-2 gap-4\">\n<a class=\"font-label-caps text-label-caps text-on-surface-variant hover:text-brass-accent hover:underline decoration-brass-accent transition-all\" href=\"#\">Invest Abia</a>\n<a class=\"font-label-caps text-label-caps text-on-surface-variant hover:text-brass-accent hover:underline decoration-brass-accent transition-all\" href=\"#\">Serve Abia</a>\n<a class=\"font-label-caps text-label-caps text-on-surface-variant hover:text-brass-accent hover:underline decoration-brass-accent transition-all\" href=\"#\">Build Abia</a>\n<a class=\"font-label-caps text-label-caps text-on-surface-variant hover:text-brass-accent hover:underline decoration-brass-accent transition-all\" href=\"#\">Open Abia</a>\n</div>\n<div class=\"flex flex-col items-start md:items-end gap-4\">\n<span class=\"font-label-caps text-label-caps text-on-surface-variant\">CITIZEN ASSISTANCE</span>\n<button class=\"px-6 py-2 bg-brass-accent text-white rounded-lg font-label-caps text-label-caps hover:opacity-90\">Contact Us</button>\n<div class=\"flex gap-4 mt-2\">\n<span class=\"material-symbols-outlined text-on-surface-variant cursor-pointer\">public</span>\n<span class=\"material-symbols-outlined text-on-surface-variant cursor-pointer\">share</span>\n</div>\n</div>\n</div>\n<div class=\"flex flex-col md:flex-row justify-between items-center pt-8 border-t border-outline-variant gap-4\">\n<p class=\"font-body-md text-sm text-on-surface-variant\">© 2024 Government of Abia State, Nigeria. Built for the Future.</p>\n<div class=\"flex gap-6\">\n<a class=\"font-label-caps text-[10px] text-on-surface-variant hover:text-primary\" href=\"#\">Privacy Policy</a>\n<a class=\"font-label-caps text-[10px] text-on-surface-variant hover:text-primary\" href=\"#\">Terms of Service</a>\n</div>\n</div>\n</div>\n</footer>\n\n",
